"use client";

import { useSession } from "next-auth/react";
import { useRouter, useSearchParams } from "next/navigation";
import { useEffect, useState, useCallback, Suspense } from "react";

interface Booking {
  id: string;
  status: string;
  paymentStatus: string;
  checkIn: string;
  checkOut: string;
  totalPrice: number;
  room: { name: string; images: string };
}

interface Favorite {
  id: string;
  room: {
    id: string;
    name: string;
    description: string;
    price: number;
    images: string;
  };
}

interface Review {
  id: string;
  rating: number;
  comment: string;
  createdAt: string;
  room: { name: string };
}

function StarRating({ rating }: { rating: number }) {
  return (
    <div className="flex items-center gap-0.5">
      {[1, 2, 3, 4, 5].map((star) => (
        <span
          key={star}
          className={`text-lg ${star <= rating ? "text-[#E8A435]" : "text-gray-300"}`}
        >
          ★
        </span>
      ))}
    </div>
  );
}

function formatDate(dateStr: string) {
  return new Date(dateStr).toLocaleDateString("en-GB", {
    day: "numeric",
    month: "short",
    year: "numeric",
  });
}

const tabs = [
  { key: "bookings", label: "Bookings", icon: "📅" },
  { key: "favorites", label: "Favorites", icon: "❤️" },
  { key: "reviews", label: "Reviews", icon: "⭐" },
];

function DashboardContent() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const searchParams = useSearchParams();
  const activeTab = searchParams.get("tab") || "bookings";

  const [bookings, setBookings] = useState<Booking[]>([]);
  const [favorites, setFavorites] = useState<Favorite[]>([]);
  const [reviews, setReviews] = useState<Review[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);

  // New review state
  const [showReviewForm, setShowReviewForm] = useState(false);
  const [reviewRoomId, setReviewRoomId] = useState("");
  const [reviewRating, setReviewRating] = useState(5);
  const [reviewComment, setReviewComment] = useState("");
  const [reviewSubmitting, setReviewSubmitting] = useState(false);

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      const [bookingsRes, favsRes, reviewsRes] = await Promise.all([
        fetch("/api/bookings"),
        fetch("/api/favorites"),
        fetch("/api/reviews"),
      ]);

      if (!bookingsRes.ok || !favsRes.ok || !reviewsRes.ok) {
        setError("Failed to load dashboard data");
        return;
      }

      setBookings(await bookingsRes.json());
      setFavorites(await favsRes.json());
      setReviews(await reviewsRes.json());
    } catch (err) {
      setError("Network error. Please try again.");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    if (status === "unauthenticated") {
      router.push("/login");
      return;
    }
    if (status === "authenticated") {
      fetchData();
    }
  }, [status, router, fetchData]);

  async function handleRemoveFavorite(favId: string) {
    try {
      const res = await fetch("/api/favorites", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ roomId: favorites.find((f) => f.id === favId)?.room.id }),
      });
      if (res.ok) {
        setFavorites((prev) => prev.filter((f) => f.id !== favId));
      }
    } catch {
      // ignore
    }
  }

  async function handleSubmitReview(e: React.FormEvent) {
    e.preventDefault();
    setReviewSubmitting(true);
    try {
      const res = await fetch("/api/reviews", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          roomId: reviewRoomId,
          rating: reviewRating,
          comment: reviewComment,
        }),
      });
      if (res.ok) {
        const newReview = await res.json();
        setReviews((prev) => [newReview, ...prev]);
        setShowReviewForm(false);
        setReviewRoomId("");
        setReviewRating(5);
        setReviewComment("");
      }
    } catch (err) {
      console.error("Error submitting review:", err);
    } finally {
      setReviewSubmitting(false);
    }
  }

  if (status === "loading") {
    return (
      <div className="min-h-screen flex items-center justify-center bg-[#FAF3E0]">
        <div className="animate-spin rounded-full h-12 w-12 border-4 border-[#1A4B7A] border-t-[#E8A435]"></div>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-[#FAF3E0] pt-24 pb-16">
      <div className="max-w-5xl mx-auto px-4 sm:px-6 lg:px-8">
        <h1 className="font-playfair text-3xl font-bold text-[#1A4B7A] mb-6">
          My Dashboard
        </h1>

        {/* Tab Navigation */}
        <div className="flex gap-2 mb-6 overflow-x-auto pb-2">
          {tabs.map((tab) => (
            <button
              key={tab.key}
              onClick={() => router.push(`/dashboard?tab=${tab.key}`)}
              className={`flex items-center gap-2 px-5 py-2.5 rounded-full text-sm font-medium whitespace-nowrap transition-colors ${
                activeTab === tab.key
                  ? "bg-[#1A4B7A] text-[#FAF3E0]"
                  : "bg-white text-gray-700 hover:bg-[#FAF3E0]"
              }`}
            >
              <span>{tab.icon}</span>
              {tab.label}
            </button>
          ))}
        </div>

        {error && (
          <div className="bg-red-50 border border-red-200 text-red-700 px-4 py-3 rounded-lg mb-6">
            {error}
          </div>
        )}

        {loading ? (
          <div className="flex items-center justify-center py-16">
            <div className="animate-spin rounded-full h-10 w-10 border-4 border-[#1A4B7A] border-t-[#E8A435]"></div>
          </div>
        ) : (
          <>
            {/* Bookings Tab */}
            {activeTab === "bookings" && (
              <div>
                {bookings.length === 0 ? (
                  <div className="bg-white rounded-2xl shadow-lg p-12 text-center">
                    <div className="text-5xl mb-4">📅</div>
                    <h3 className="font-playfair text-xl font-bold text-[#1A4B7A] mb-2">
                      No bookings yet
                    </h3>
                    <p className="text-gray-600 mb-4">
                      Browse our rooms and make your first reservation.
                    </p>
                    <a
                      href="/rooms"
                      className="inline-block bg-[#C75B39] text-[#FAF3E0] px-6 py-2.5 rounded-lg font-medium hover:bg-[#C75B39]/90 transition-colors"
                    >
                      Browse Rooms
                    </a>
                  </div>
                ) : (
                  <div className="space-y-4">
                    {bookings.map((booking) => (
                      <div
                        key={booking.id}
                        className="bg-white rounded-xl shadow-md p-5 flex flex-col sm:flex-row sm:items-center gap-4"
                      >
                        <div className="flex-1">
                          <h3 className="font-playfair text-lg font-bold text-[#1A4B7A]">
                            {booking.room?.name || "Unknown Room"}
                          </h3>
                          <p className="text-sm text-gray-600 mt-1">
                            {formatDate(booking.checkIn)} — {formatDate(booking.checkOut)}
                          </p>
                        </div>
                        <div className="flex items-center gap-4">
                          <span className="text-lg font-bold text-[#1A4B7A]">
                            €{booking.totalPrice}
                          </span>
                          <span
                            className={`text-xs px-3 py-1 rounded-full font-medium ${
                              booking.paymentStatus === "paid"
                                ? "bg-[#5A8F6E]/10 text-[#5A8F6E]"
                                : "bg-[#E8A435]/10 text-[#C75B39]"
                            }`}
                          >
                            {booking.paymentStatus === "paid" ? "Paid" : "Pending"}
                          </span>
                          <span className="text-xs px-3 py-1 rounded-full bg-[#1A4B7A]/10 text-[#1A4B7A] font-medium capitalize">
                            {booking.status}
                          </span>
                        </div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}

            {/* Favorites Tab */}
            {activeTab === "favorites" && (
              <div>
                {favorites.length === 0 ? (
                  <div className="bg-white rounded-2xl shadow-lg p-12 text-center">
                    <div className="text-5xl mb-4">❤️</div>
                    <h3 className="font-playfair text-xl font-bold text-[#1A4B7A] mb-2">
                      No favorites yet
                    </h3>
                    <p className="text-gray-600 mb-4">
                      Heart the rooms you love to save them here.
                    </p>
                    <a
                      href="/rooms"
                      className="inline-block bg-[#C75B39] text-[#FAF3E0] px-6 py-2.5 rounded-lg font-medium hover:bg-[#C75B39]/90 transition-colors"
                    >
                      Browse Rooms
                    </a>
                  </div>
                ) : (
                  <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-4">
                    {favorites.map((fav) => {
                      const images = (() => {
                        try {
                          return JSON.parse(fav.room.images);
                        } catch {
                          return [];
                        }
                      })();
                      return (
                        <div
                          key={fav.id}
                          className="bg-white rounded-xl shadow-md overflow-hidden group"
                        >
                          <div className="relative h-48 overflow-hidden">
                            <img
                              src={images[0] || "https://images.unsplash.com/photo-1520250497591-112f2f40a3f4?w=800&q=80"}
                              alt={fav.room.name}
                              className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-300"
                            />
                            <div className="absolute inset-0 bg-gradient-to-t from-black/40 to-transparent" />
                            <button
                              onClick={() => handleRemoveFavorite(fav.id)}
                              className="absolute top-3 right-3 bg-white/90 backdrop-blur rounded-full p-2 hover:bg-[#C75B39] hover:text-white transition-colors"
                              aria-label="Remove from favorites"
                            >
                              <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 24 24">
                                <path d="M6 18L18 6M6 6l12 12" stroke="currentColor" strokeWidth="2" strokeLinecap="round" fill="none" />
                              </svg>
                            </button>
                          </div>
                          <div className="p-4">
                            <h3 className="font-playfair font-bold text-[#1A4B7A]">
                              {fav.room.name}
                            </h3>
                            <p className="text-sm text-gray-600 mt-1">
                              €{fav.room.price}/night
                            </p>
                          </div>
                        </div>
                      );
                    })}
                  </div>
                )}
              </div>
            )}

            {/* Reviews Tab */}
            {activeTab === "reviews" && (
              <div>
                <div className="flex items-center justify-between mb-4">
                  <h2 className="font-playfair text-xl font-bold text-[#1A4B7A]">
                    My Reviews
                  </h2>
                  <button
                    onClick={() => setShowReviewForm(!showReviewForm)}
                    className="bg-[#C75B39] text-[#FAF3E0] px-4 py-2 rounded-lg text-sm font-medium hover:bg-[#C75B39]/90 transition-colors"
                  >
                    {showReviewForm ? "Cancel" : "+ New Review"}
                  </button>
                </div>

                {showReviewForm && (
                  <form
                    onSubmit={handleSubmitReview}
                    className="bg-white rounded-xl shadow-lg p-6 mb-6"
                  >
                    <h3 className="font-playfair text-lg font-bold text-[#1A4B7A] mb-4">
                      Write a Review
                    </h3>
                    <div className="space-y-4">
                      <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">
                          Room ID
                        </label>
                        <input
                          type="text"
                          value={reviewRoomId}
                          onChange={(e) => setReviewRoomId(e.target.value)}
                          required
                          className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-[#E8A435]"
                          placeholder="Enter room ID"
                        />
                      </div>
                      <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">
                          Rating
                        </label>
                        <div className="flex gap-2">
                          {[1, 2, 3, 4, 5].map((star) => (
                            <button
                              key={star}
                              type="button"
                              onClick={() => setReviewRating(star)}
                              className={`text-2xl ${star <= reviewRating ? "text-[#E8A435]" : "text-gray-300"}`}
                            >
                              ★
                            </button>
                          ))}
                        </div>
                      </div>
                      <div>
                        <label className="block text-sm font-medium text-gray-700 mb-1">
                          Comment
                        </label>
                        <textarea
                          value={reviewComment}
                          onChange={(e) => setReviewComment(e.target.value)}
                          required
                          rows={3}
                          className="w-full border border-gray-300 rounded-lg px-4 py-2 focus:outline-none focus:ring-2 focus:ring-[#E8A435]"
                          placeholder="Share your experience..."
                        />
                      </div>
                      <button
                        type="submit"
                        disabled={reviewSubmitting}
                        className="bg-[#1A4B7A] text-[#FAF3E0] px-6 py-2.5 rounded-lg font-medium hover:bg-[#1A4B7A]/90 transition-colors disabled:opacity-50"
                      >
                        {reviewSubmitting ? "Submitting..." : "Submit Review"}
                      </button>
                    </div>
                  </form>
                )}

                {reviews.length === 0 && !showReviewForm ? (
                  <div className="bg-white rounded-2xl shadow-lg p-12 text-center">
                    <div className="text-5xl mb-4">⭐</div>
                    <h3 className="font-playfair text-xl font-bold text-[#1A4B7A] mb-2">
                      No reviews yet
                    </h3>
                    <p className="text-gray-600">
                      Stayed with us? Share your experience!
                    </p>
                  </div>
                ) : (
                  <div className="space-y-4">
                    {reviews.map((review) => (
                      <div
                        key={review.id}
                        className="bg-white rounded-xl shadow-md p-5"
                      >
                        <div className="flex items-start justify-between">
                          <div>
                            <h3 className="font-playfair font-bold text-[#1A4B7A]">
                              {review.room?.name || "Unknown Room"}
                            </h3>
                            <StarRating rating={review.rating} />
                          </div>
                          <span className="text-xs text-gray-500">
                            {formatDate(review.createdAt)}
                          </span>
                        </div>
                        <p className="text-gray-700 mt-3">{review.comment}</p>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}
          </>
        )}
      </div>
    </div>
  );
}

export default function DashboardPage() {
  return (
    <Suspense fallback={<div className="min-h-screen flex items-center justify-center bg-[#FAF3E0]"><div className="animate-spin rounded-full h-12 w-12 border-4 border-[#1A4B7A] border-t-[#E8A435]"></div></div>}>
      <DashboardContent />
    </Suspense>
  );

}
